func normalizeMoney(units int64, nanos int32) (int64, int32) {
	if nanos <= -1e9 || nanos >= 1e9 {
		units += int64(nanos / 1e9)
		nanos = nanos % 1e9
	}
	if units > 0 && nanos < 0 {
		units--
		nanos += 1e9
	}
	if units < 0 && nanos > 0 {
		units++
		nanos -= 1e9
	}
	return units, nanos
}

func cmpMoney(aUnits int64, aNanos int32, bUnits int64, bNanos int32) int {
	aUnits, aNanos = normalizeMoney(aUnits, aNanos)
	bUnits, bNanos = normalizeMoney(bUnits, bNanos)
	if aUnits < bUnits {
		return -1
	}
	if aUnits > bUnits {
		return 1
	}
	if aNanos < bNanos {
		return -1
	}
	if aNanos > bNanos {
		return 1
	}
	return 0
}

func addMoney(aUnits int64, aNanos int32, bUnits int64, bNanos int32) (int64, int32) {
	u := aUnits + bUnits
	n := aNanos + bNanos
	return normalizeMoney(u, n)
}

func subMoney(aUnits int64, aNanos int32, bUnits int64, bNanos int32) (int64, int32) {
	u := aUnits - bUnits
	n := aNanos - bNanos
	return normalizeMoney(u, n)
}

